// NOTE: Logo base64 strings dipertahankan sama persis dari file asli. Disingkat di sini untuk keterbacaan.
// Pastikan logoBase64 dari file ASLI tetap digunakan.

function getBrandingData(ptName) {
  let target = (ptName || "").toString().trim().replace(/\./g, '').toLowerCase();
  const keys = Object.keys(COMPANY_BRANDING);
  for (let i = 0; i < keys.length; i++) {
    let cleanKey = keys[i].replace(/\./g, '').toLowerCase();
    if (target && (cleanKey === target || target.includes(cleanKey) || cleanKey.includes(target))) {
      return COMPANY_BRANDING[keys[i]];
    }
  }
  if (keys.length > 0) return COMPANY_BRANDING[keys[0]];
  return null;
}

