function prosesLogin(username, password) {
  try {
    const sheet = SpreadsheetApp.openByUrl(SHEET_URL).getSheetByName(KARYAWAN_SHEET_NAME);
    const lastRow = sheet.getLastRow();
    if (lastRow < 1) return { success: false, message: 'Data tidak ditemukan!' };
    const data = sheet.getRange(1, 1, lastRow, 15).getDisplayValues();
    const inputHash = hashPassword(password);
    const inputUser = username.toString().trim().toLowerCase();

    for (let i = 1; i < data.length; i++) {
      let dbNIK = data[i][0] ? data[i][0].toString().trim().toLowerCase() : '';
      let dbPassword = data[i][4] ? data[i][4].toString().trim() : '';
      if (dbNIK === inputUser) {
        if (dbPassword === inputHash || dbPassword === password) {
          const rawPt = data[i][1];
          let namaPT = rawPt ? rawPt.toString().trim() : "";
          let brandData = getBrandingData(namaPT);
          let dbEmail = data[i][3] ? data[i][3].toString().trim().toLowerCase() : '';
          let ext = data[i].slice(11);
          return {
            success: true,
            userData: {
              id: data[i][0],
              ptName: namaPT,
              nama: data[i][2],
              email: dbEmail,
              peran: data[i][5],
              divisi: data[i][6],
              jabatan: data[i][7],
              tanggalMasuk: data[i][8] || '',
              status: data[i][9],
              // sisaCuti di sini adalah legacy static quota.
              // Untuk tampilan sisa cuti FIFO yang akurat, frontend harus memanggil
              // getUsableQuotaForUser(userData.nama) secara terpisah.
              sisaCuti: data[i][10],
              rawPtName: rawPt !== undefined ? rawPt.toString() : "UNDEFINED_OR_EMPTY",
              branding: brandData,
              extended: ext
            }
          };
        }
      }
    }
    return { success: false, message: 'NIK atau Password salah!' };
  } catch (error) { return { success: false, message: error.message }; }
}

