/**
 * simpanDataCuti — Simpan pengajuan cuti dengan validasi kuota FIFO.
 *
 * Validasi sebelum menyimpan:
 * 1. Hitung kuota FIFO yang tersedia via getUsableQuotaForUser.
 * 2. Hitung total hari dari semua pengajuan "Menunggu Persetujuan" yang belum diproses.
 * 3. Tolak jika (lama_cuti_baru + total_pending) > kuota_tersedia.
 */
function simpanDataCuti(dataForm) {
  try {
    const ss = SpreadsheetApp.openByUrl(SHEET_URL);
    const cutiSheet = ss.getSheetByName(CUTI_SHEET_NAME);
    const lamaCutiBaru = parseInt(dataForm.lama_cuti) || 0;
    const targetName = (dataForm.nama || '').toString().trim().toLowerCase();

    // 1. Hitung kuota FIFO yang tersedia hari ini
    const availableQuota = getUsableQuotaForUser(dataForm.nama);

    // 2. Hitung total hari dari pengajuan yang masih "Menunggu Persetujuan"
    let pendingDays = 0;
    if (cutiSheet) {
      const cutiData = cutiSheet.getDataRange().getDisplayValues();
      for (let i = 1; i < cutiData.length; i++) {
        const rowNama = cutiData[i][1] ? cutiData[i][1].toString().trim().toLowerCase() : '';
        const rowStatus = cutiData[i][12] ? cutiData[i][12].toString().trim() : '';
        if (rowNama === targetName && rowStatus === 'Menunggu Persetujuan') {
          pendingDays += (parseInt(cutiData[i][8]) || 0);
        }
      }
    }

    // 3. Validasi: tolak jika melebihi kuota
    if ((lamaCutiBaru + pendingDays) > availableQuota) {
      return {
        status: 'error',
        message: `Sisa kuota cuti (FIFO) Anda tidak mencukupi untuk pengajuan ini. Kuota tersedia: ${availableQuota} hari, sudah pending: ${pendingDays} hari, diminta: ${lamaCutiBaru} hari.`
      };
    }

    // 4. Validasi lolos — simpan ke sheet
    cutiSheet.appendRow([
      new Date(), dataForm.nama, dataForm.jabatan, dataForm.divisi, dataForm.penempatan,
      dataForm.jenis_cuti, dataForm.tanggal_mulai, dataForm.tanggal_selesai, dataForm.lama_cuti,
      dataForm.alamat_cuti, dataForm.no_hp, dataForm.pengganti, 'Menunggu Persetujuan', dataForm.keterangan || ''
    ]);

    // 5. Notifikasi email ke admin
    try {
      MailApp.sendEmail({
        to: ADMIN_EMAIL,
        subject: `[HRIS] Pengajuan Cuti Baru - ${dataForm.nama}`,
        body: `Ada pengajuan cuti baru dari ${dataForm.nama} (${lamaCutiBaru} hari). Silakan login ke Portal HRIS Admin.`,
        name: SENDER_NAME
      });
    } catch (e) { }

    return { status: 'success', message: 'Pengajuan cuti berhasil dikirim!' };
  } catch (error) { return { status: 'error', message: error.toString() }; }
}

function submitRequest(formData) {
  try {
    const sheet = SpreadsheetApp.openByUrl(SHEET_URL).getSheetByName(REQUEST_LOG_SHEET_NAME);
    if (!sheet) throw new Error("Sheet Permintaan ATK tidak ditemukan.");
    const timestamp = new Date();
    const requestId = `REQ-${timestamp.getTime()}`;
    formData.requestedItems.forEach(item => {
      sheet.appendRow([requestId, timestamp, formData.employeeName, formData.employeeEmail, formData.department, item.name, item.quantity, 'Menunggu Persetujuan', '']);
    });
    try { MailApp.sendEmail({ to: ADMIN_EMAIL, subject: `[Logistik] Permintaan Barang Baru: ${formData.employeeName}`, body: `Ada permintaan ATK baru dari ${formData.employeeName}.`, name: SENDER_NAME }); } catch (e) { }
    return { success: true, message: 'Permintaan ATK berhasil dikirim.' };
  } catch (error) { return { success: false, message: error.message }; }
}

