function getUserRequests(email) {
  try {
    const data = SpreadsheetApp.openByUrl(SHEET_URL).getSheetByName(REQUEST_LOG_SHEET_NAME).getDataRange().getDisplayValues();
    const target = (email || '').toString().trim().toLowerCase();
    const requests = [];
    for (let i = data.length - 1; i > 0; i--) {
      let sheetEmail = data[i][3] ? data[i][3].toString().trim().toLowerCase() : '';
      if (sheetEmail === target) {
        requests.push({ rowNum: i + 1, timestamp: data[i][1], itemName: data[i][5], quantity: data[i][6], status: data[i][7], proofLink: data[i][8] || null });
      }
    }
    return requests;
  } catch (e) { return []; }
}

function getUserCuti(nama) {
  try {
    const sheet = SpreadsheetApp.openByUrl(SHEET_URL).getSheetByName(CUTI_SHEET_NAME);
    if (!sheet) return [];
    const data = sheet.getDataRange().getDisplayValues();
    const target = (nama || '').toString().trim().toLowerCase();
    const requests = [];
    for (let i = data.length - 1; i > 0; i--) {
      let sheetName = data[i][1] ? data[i][1].toString().trim().toLowerCase() : '';
      if (sheetName === target) {
        let st = data[i][12] ? data[i][12].toString() : 'Menunggu Persetujuan';
        requests.push({
          timestamp: data[i][0], nama: data[i][1], jabatan: data[i][2],
          divisi: data[i][3], penempatan: data[i][4], jenis: data[i][5],
          tglMulai: data[i][6], tglSelesai: data[i][7], lama: data[i][8],
          alamat: data[i][9], noHp: data[i][10], pengganti: data[i][11],
          status: st, keterangan: data[i][13] || ''
        });
      }
    }
    return requests;
  } catch (e) { return []; }
}

function confirmPickupWithPhoto(fileData, rowNum) {
  try {
    const sheet = SpreadsheetApp.openByUrl(SHEET_URL).getSheetByName(REQUEST_LOG_SHEET_NAME);
    const folder = DriveApp.getFolderById(DRIVE_FOLDER_ID);
    const blob = Utilities.newBlob(Utilities.base64Decode(fileData.base64Data.split(',')[1]), fileData.mimeType || 'image/png', fileData.fileName);
    const fileUrl = folder.createFile(blob).setSharing(DriveApp.Access.ANYONE_WITH_LINK, DriveApp.Permission.VIEW).getUrl();
    sheet.getRange(rowNum, 8).setValue('Sudah Diambil');
    sheet.getRange(rowNum, 9).setValue(fileUrl);
    return { success: true, newStatus: 'Sudah Diambil', proofLink: fileUrl };
  } catch (e) { return { success: false, message: 'Gagal menyimpan foto: ' + e.message }; }
}

function getRoleInfoByEmail(email) {
  if (!email) return null;
  try {
    const sheet = SpreadsheetApp.openByUrl(SHEET_URL).getSheetByName(KARYAWAN_SHEET_NAME);
    const data = sheet.getDataRange().getDisplayValues();
    const target = email.toString().trim().toLowerCase();
    for (let i = 1; i < data.length; i++) {
      let dbEmail = data[i][3] ? data[i][3].toString().trim().toLowerCase() : '';
      if (dbEmail === target) {
        return {
          ptName: data[i][1] ? data[i][1].toString().trim() : "",
          divisi: data[i][6] ? data[i][6].toString().trim() : "",
          peran: data[i][5] ? data[i][5].toString().trim() : ""
        };
      }
    }
  } catch (e) { }
  return null;
}

function getAllCuti(callerEmail) {
  const callerInfo = callerEmail ? getRoleInfoByEmail(callerEmail) : null;
  const isAtasan = callerInfo && callerInfo.peran.toLowerCase() === 'atasan';
  const rolePt = isAtasan ? callerInfo.ptName : null;
  const roleDivisi = isAtasan ? callerInfo.divisi : null;
  const ss = SpreadsheetApp.openByUrl(SHEET_URL);
  const data = ss.getSheetByName(CUTI_SHEET_NAME).getDataRange().getDisplayValues();
  const ptMap = getEmployeePtMap();
  const requests = [];
  for (let i = data.length - 1; i > 0; i--) {
    const nama = data[i][1];
    const empDivisi = data[i][3] ? data[i][3].toString().trim() : "";
    const empPtName = ptMap[nama.toString().trim().toLowerCase()] || "-";
    if (isAtasan && (empPtName !== rolePt || empDivisi !== roleDivisi)) continue;
    requests.push({
      rowNum: i + 1,
      timestamp: data[i][0],
      nama: nama,
      divisi: data[i][3],
      jenis: data[i][5],
      tglMulai: data[i][6],
      tglSelesai: data[i][7],
      lama: data[i][8],
      alasan: data[i][9],
      status: data[i][12],
      keterangan: data[i][13] || '',
      ptName: empPtName
    });
  }
  return requests;
}

/**
 * FIX KRITIS: processCutiApproval
 *
 * PERUBAHAN:
 * 1. HAPUS blok update sisaCuti di spreadsheet.
 *    Alasan: Sistem FIFO menghitung kuota secara dinamis dari histori cuti di sheet Data Cuti.
 *    Kolom sisaCuti (index 10) hanya berperan sebagai "legacy quota 2025" (modal awal),
 *    dan TIDAK BOLEH diubah saat ada approval cuti 2026+.
 *    Jika diubah, maka calculateUsableQuota akan menghasilkan angka yang salah.
 *
 * 2. Logika status dan pengiriman email tetap sama.
 */
function processCutiApproval(rowNum, isApproved, reason, namaKaryawan, lamaCuti) {
  try {
    const sheetCuti = SpreadsheetApp.openByUrl(SHEET_URL).getSheetByName(CUTI_SHEET_NAME);
    const dataCuti = sheetCuti.getDataRange().getValues();
    const status = isApproved ? 'Disetujui' : `Ditolak: ${reason}`;

    // Update status di kolom 13 (1-indexed) = index 12 (0-indexed)
    sheetCuti.getRange(rowNum, 13).setValue(status);

    // Kirim notifikasi email ke karyawan
    const reqData = dataCuti[rowNum - 1];
    const jenisCuti = reqData[5];
    const tglMulai = reqData[6];
    const tglSelesai = reqData[7];
    const emailKaryawan = getEmailByName(namaKaryawan);
    if (emailKaryawan) sendCutiEmail(emailKaryawan, namaKaryawan, status, jenisCuti, tglMulai, tglSelesai, reason);

    // CATATAN ARSITEKTUR:
    // Tidak ada lagi update manual ke kolom sisaCuti di sheet Data Karyawan.
    // Kuota sisa cuti dihitung dinamis oleh calculateUsableQuota() berdasarkan
    // semua baris berstatus 'Disetujui' di sheet Data Cuti.
    // Ini memastikan konsistensi sistem FIFO 6-bulan rolling.

    return { success: true, message: 'Status Cuti diupdate.' };
  } catch (e) { return { success: false, message: e.message }; }
}

function getKaryawanData(callerEmail) {
  const callerInfo = callerEmail ? getRoleInfoByEmail(callerEmail) : null;
  const isAtasan = callerInfo && callerInfo.peran.toLowerCase() === 'atasan';
  const rolePt = isAtasan ? callerInfo.ptName : null;
  const roleDivisi = isAtasan ? callerInfo.divisi : null;
  const sheet = SpreadsheetApp.openByUrl(SHEET_URL).getSheetByName(KARYAWAN_SHEET_NAME);
  const data = sheet.getDataRange().getDisplayValues();
  const headers = data[0];
  const karyawan = [];
  for (let i = 1; i < data.length; i++) {
    const empPtName = data[i][1] ? data[i][1].toString().trim() : "-";
    const empDivisi = data[i][6] ? data[i][6].toString().trim() : "";
    if (isAtasan && (empPtName !== rolePt || empDivisi !== roleDivisi)) continue;
    let extendedData = [];
    for (let j = 11; j < headers.length; j++) {
      if (headers[j]) {
        extendedData.push({ label: headers[j].toString().trim(), value: data[i][j] ? data[i][j].toString().trim() : "-" });
      }
    }
    karyawan.push({
      rowNum: i + 1,
      id: data[i][0],
      ptName: empPtName,
      nama: data[i][2],
      email: data[i][3],
      peran: data[i][5],
      divisi: data[i][6],
      jabatan: data[i][7],
      tanggalMasuk: data[i][8] || '',
      status: data[i][9] || "-",
      sisaCuti: data[i][10],
      extended: extendedData
    });
  }
  return karyawan;
}

function getExtendedHeaders() {
  try {
    const sheet = SpreadsheetApp.openByUrl(SHEET_URL).getSheetByName(KARYAWAN_SHEET_NAME);
    const headers = sheet.getDataRange().getDisplayValues()[0];
    return headers.slice(11).filter(h => h.trim() !== "");
  } catch (e) { return []; }
}


// ============================================================
// DYNAMIC LEAVE ACCRUAL ENGINE — FIFO + 6-MONTH ROLLING EXPIRY
// ============================================================

/**
 * getMassLeaveDatesFromSS — Ambil semua tanggal Cuti Bersama Idul Fitri tahun berjalan.
 *
 * FIX: Hapus filter `d <= today`.
 * Alasan: Kita perlu SEMUA tanggal Cuti Bersama dalam tahun berjalan (bukan hanya yang sudah lewat)
 * agar sistem bisa langsung melihat accrual akhir tahun mana yang akan dikonsumsi (pre-deduction).
 * Ini tidak mempengaruhi usable balance hari ini (karena accrual belum earned tetap tidak dihitung),
 * tapi memberi gambaran kuota yang lebih akurat untuk perencanaan.
 *
 * Hanya cocokkan "Cuti Bersama Idul Fitri" sesuai requirement #7, bukan semua "Cuti Bersama".
 *
 * @param {Spreadsheet} ss - SpreadsheetApp object
 * @returns {Date[]} Array tanggal Cuti Bersama Idul Fitri tahun berjalan
 */
function getMassLeaveDatesFromSS(ss) {
  var massLeaves = [];
  try {
    var liburSheet = ss.getSheetByName('Libur Nasional');
    if (!liburSheet) return massLeaves;
    var data = liburSheet.getDataRange().getDisplayValues();
    var currentYear = new Date().getFullYear();

    for (var i = 1; i < data.length; i++) {
      var d = parseIndoDate(data[i][0]);
      if (isNaN(d.getTime())) continue;
      if (d.getFullYear() !== currentYear) continue;

      // FIX: Deteksi spesifik "Cuti Bersama Idul Fitri" sesuai requirement #7.
      // Kolom B (index 1) = Nama Libur.
      // Cocokkan: mengandung "cuti bersama" DAN ("idul fitri" ATAU "lebaran").
      // Ini menghindari Cuti Bersama lain (misal Cuti Bersama Natal) ikut terpotong.
      var namaLibur = (data[i][1] || '').toString().toLowerCase();
      var isCutiBersamaIdulFitri = namaLibur.includes('cuti bersama') &&
        (namaLibur.includes('idul fitri') || namaLibur.includes('lebaran'));

      if (isCutiBersamaIdulFitri) {
        d.setHours(0, 0, 0, 0);
        massLeaves.push(d);
      }
    }
  } catch (e) { }
  return massLeaves;
}

/**
 * calculateUsableQuota — Engine FIFO utama untuk menghitung sisa cuti yang bisa dipakai.
 *
 * ATURAN SISTEM:
 * 1. Karyawan join sebelum 2026 (legacy): Sisa cuti 2025 (statisQuota) berlaku hingga 31 Maret 2026.
 *    Setelah itu hangus. Accrual 2026 mulai 1 Februari 2026.
 *
 * 2. Karyawan join 2026+: Mendapat 1 accrual setelah melewati tiap 1 bulan.
 *    Accrual pertama = 1 bulan setelah tanggal join.
 *
 * 3. Setiap accrual berlaku 6 bulan sejak diperoleh (rolling). Setelah itu hangus.
 *    Contoh: accrual Januari 2026 → berlaku s.d. 31 Juni 2026 (expiry 1 Juli).
 *
 * 4. Cuti Bersama Idul Fitri otomatis dipotong dari accrual AKHIR TAHUN (LIFO dalam tahun).
 *    Misal 3 hari Cuti Bersama → gunakan accrual Desember, November, Oktober.
 *
 * 5. Karyawan yang join SETELAH tanggal Cuti Bersama tidak kena potongan.
 *
 * 6. Penggunaan cuti reguler memakai accrual TERLAMA yang valid (FIFO) untuk mencegah hangus.
 *
 * @param {string} tanggalMasukStr  - Tanggal masuk karyawan
 * @param {Array}  approvedLeaves   - [{tglMulai, lama}] cuti yang sudah disetujui
 * @param {*}      statisQuotaRaw   - Sisa cuti 2025 dari spreadsheet (legacy quota)
 * @param {Date[]} massLeaveDates   - Tanggal-tanggal Cuti Bersama Idul Fitri
 * @returns {number} Jumlah hari cuti yang bisa dipakai hari ini
 */
function calculateUsableQuota(tanggalMasukStr, approvedLeaves, statisQuotaRaw, massLeaveDates) {
  if (!tanggalMasukStr) return 0;

  const joinDate = parseIndoDate(tanggalMasukStr);
  if (isNaN(joinDate.getTime())) return 0;

  const today = new Date();
  today.setHours(0, 0, 0, 0);

  const statisQuota = parseInt(statisQuotaRaw) || 0;
  const regulationStart = new Date(2026, 0, 1);    // 1 Jan 2026 = awal sistem FIFO
  const grandfatherExpiry = new Date(2026, 2, 31); // 31 Maret 2026 = batas akhir legacy quota

  const accruals = [];
  let currentAccrualDate;

  // ── LANGKAH 1: INISIALISASI ──────────────────────────────────────────────
  if (joinDate < regulationStart) {
    // KARYAWAN LEGACY (join sebelum 2026):
    // Masukkan statisQuota sebagai saldo carry-over 2025.
    // Semua berstatus "earned 31 Des 2025", hangus 31 Maret 2026.
    for (let i = 0; i < statisQuota; i++) {
      accruals.push({
        earned: new Date(2025, 11, 31), // 31 Des 2025
        expiry: new Date(2026, 2, 31),  // 31 Mar 2026 (sesuai requirement #1)
        isUsed: false
      });
    }
    // Accrual FIFO 2026 mulai Feb 1 (untuk menyelesaikan Januari 2026).
    // Kita skip Jan 1 agar tidak double-dip dengan legacy quota.
    currentAccrualDate = new Date(2026, 1, 1); // 1 Feb 2026
  } else {
    // KARYAWAN BARU (join 2026+):
    // Accrual pertama = 1 bulan setelah join.
    currentAccrualDate = new Date(joinDate);
    currentAccrualDate.setMonth(currentAccrualDate.getMonth() + 1);
    currentAccrualDate.setDate(1); // Normalisasi ke tanggal 1
  }

  // ── LANGKAH 2: GENERATE ACCRUAL BULANAN s.d. AKHIR TAHUN BERJALAN ───────
  const endOfYear = new Date(today.getFullYear(), 11, 31);
  while (currentAccrualDate <= endOfYear) {
    let earned = new Date(currentAccrualDate);
    let expiry = new Date(earned);
    expiry.setMonth(expiry.getMonth() + 6); // Berlaku 6 bulan
    accruals.push({ earned: earned, expiry: expiry, isUsed: false });
    currentAccrualDate.setMonth(currentAccrualDate.getMonth() + 1);
  }

  // ── LANGKAH 3: DEDUCT CUTI BERSAMA IDUL FITRI (LIFO DARI AKHIR TAHUN) ───
  // Untuk setiap hari Cuti Bersama:
  //   - Ambil accrual TERBARU dalam tahun yang sama (LIFO: Des → Nov → Okt → dst)
  //   - Tandai sebagai used
  //   - Karyawan yang join SETELAH tanggal Cuti Bersama: dilewati
  //
  // Ini memenuhi requirement #4 dan #5.
  (massLeaveDates || []).forEach(massDay => {
    // Requirement #6: Lewati jika karyawan baru join setelah hari Cuti Bersama ini
    if (massDay < joinDate) return;

    const targetYear = massDay.getFullYear();

    // Cari accrual tahun yang sama, belum dipakai, belum expired saat Cuti Bersama terjadi
    const validAccruals = accruals.filter(acc =>
      !acc.isUsed &&
      acc.earned.getFullYear() === targetYear &&
      acc.expiry > massDay
    );

    if (validAccruals.length > 0) {
      // LIFO: sort descending → ambil accrual paling akhir tahun (Des, Nov, Okt, ...)
      validAccruals.sort((a, b) => b.earned - a.earned);
      validAccruals[0].isUsed = true;
    } else {
      // Fallback: jika tidak ada accrual tahun yang sama yang cocok,
      // cari accrual valid FIFO dari mana saja
      const fallback = accruals.find(acc =>
        !acc.isUsed &&
        acc.earned <= massDay &&
        acc.expiry > massDay
      );
      if (fallback) fallback.isUsed = true;
    }
  });

  // ── LANGKAH 4: BUAT DAFTAR HARI CUTI REGULER (dari form yang disetujui) ─
  // Expand setiap baris approved leave menjadi hari-hari individual
  const normalLeafDays = [];
  (approvedLeaves || []).forEach(leave => {
    const startDate = parseIndoDate(leave.tglMulai);
    if (isNaN(startDate.getTime())) return;
    const count = parseInt(leave.lama) || 0;
    for (let i = 0; i < count; i++) {
      let d = new Date(startDate);
      d.setDate(d.getDate() + i);
      normalLeafDays.push(d);
    }
  });

  // Hilangkan hari yang sudah ditangani oleh Cuti Bersama (mencegah double-deduction)
  const filteredNormalLeafDays = normalLeafDays.filter(nd => {
    let ndTime = new Date(nd).setHours(0, 0, 0, 0);
    return !(massLeaveDates || []).some(md => md.getTime() === ndTime);
  });

  // ── LANGKAH 5: DEDUCT CUTI REGULER (FIFO — accrual terlama dulu) ─────────
  filteredNormalLeafDays.sort((a, b) => a - b); // Urutkan kronologis

  filteredNormalLeafDays.forEach(day => {
    const targetDay = new Date(day);
    targetDay.setHours(0, 0, 0, 0);

    // FIFO: find() mengembalikan elemen pertama (= accrual terlama)
    const validAccrual = accruals.find(acc =>
      !acc.isUsed &&
      acc.earned <= targetDay && // Accrual harus sudah earned saat cuti diambil
      acc.expiry > targetDay      // Accrual belum hangus saat cuti diambil
    );

    if (validAccrual) {
      validAccrual.isUsed = true;
    }
    // Jika tidak ada accrual valid: cuti ini "overdraft" (tidak memiliki kuota saat diambil).
    // Tidak ada yang diubah, balance tidak bertambah minus.
  });

  // ── LANGKAH 6: HITUNG SALDO USABLE HARI INI ─────────────────────────────
  // Hanya accrual yang: (1) sudah earned ≤ hari ini, (2) belum hangus, (3) belum dipakai
  const usableBalance = accruals.filter(acc =>
    !acc.isUsed &&
    acc.earned <= today && // Sudah earned (bulannya sudah terlewati)
    acc.expiry > today     // Belum hangus
  ).length;

  return usableBalance;
}

/**
 * getMasterCutiData — Data master cuti semua karyawan dengan kuota FIFO.
 * Digunakan untuk tampilan admin.
 */
function getMasterCutiData() {
  var ss = SpreadsheetApp.openByUrl(SHEET_URL);
  var karSheet = ss.getSheetByName(KARYAWAN_SHEET_NAME);
  var cutiSheet = ss.getSheetByName(CUTI_SHEET_NAME);

  var karData = karSheet.getRange(1, 1, karSheet.getLastRow(), Math.max(karSheet.getLastColumn(), 11)).getDisplayValues();
  var cutiData = cutiSheet ? cutiSheet.getDataRange().getDisplayValues() : [];

  // Bangun map: namaKaryawan (lowercase) → array approved leaves
  var leavesMap = {};
  for (var ci = 1; ci < cutiData.length; ci++) {
    var nama = cutiData[ci][1] ? cutiData[ci][1].toString().trim().toLowerCase() : '';
    var status = cutiData[ci][12] ? cutiData[ci][12].toString() : '';
    if (nama && status === 'Disetujui') {
      if (!leavesMap[nama]) leavesMap[nama] = [];
      leavesMap[nama].push({ tglMulai: cutiData[ci][6], lama: cutiData[ci][8] });
    }
  }

  var massLeaveDates = getMassLeaveDatesFromSS(ss);
  var result = [];

  for (var ki = 1; ki < karData.length; ki++) {
    var empNama = karData[ki][2] ? karData[ki][2].toString().trim() : '';
    var empNamaLower = empNama.toLowerCase();
    var tanggalMasuk = karData[ki][8] || '';
    var staticQuotaVal = karData[ki][10] || 0;
    var approvedLeaves = leavesMap[empNamaLower] || [];
    var usableQuota = calculateUsableQuota(tanggalMasuk, approvedLeaves, staticQuotaVal, massLeaveDates);

    var cutiDiambil = 0;
    for (var cl = 0; cl < approvedLeaves.length; cl++) {
      cutiDiambil += (parseInt(approvedLeaves[cl].lama) || 0);
    }

    result.push({
      nik: karData[ki][0] || '-',
      ptName: karData[ki][1] || '-',
      nama: empNama,
      divisi: karData[ki][6] || '-',
      jabatan: karData[ki][7] || '-',
      tanggalMasuk: tanggalMasuk,
      staticQuota: karData[ki][10] || 0,
      cutiDiambil: cutiDiambil,
      usableQuota: usableQuota
    });
  }
  return result;
}

/**
 * getUsableQuotaForUser — Hitung kuota FIFO untuk satu karyawan (dipakai di portal karyawan).
 *
 * @param {string} nama - Nama karyawan
 * @returns {number} Sisa kuota cuti yang bisa dipakai hari ini
 */
function getUsableQuotaForUser(nama) {
  try {
    var ss = SpreadsheetApp.openByUrl(SHEET_URL);
    var karSheet = ss.getSheetByName(KARYAWAN_SHEET_NAME);
    var cutiSheet = ss.getSheetByName(CUTI_SHEET_NAME);

    var karData = karSheet.getRange(1, 1, karSheet.getLastRow(), Math.max(karSheet.getLastColumn(), 11)).getDisplayValues();
    var targetName = (nama || '').toString().trim().toLowerCase();
    var tanggalMasuk = '';
    var staticQuotaVal = 0;

    for (var i = 1; i < karData.length; i++) {
      var dbName = karData[i][2] ? karData[i][2].toString().trim().toLowerCase() : '';
      if (dbName === targetName) {
        tanggalMasuk = karData[i][8] || '';
        staticQuotaVal = karData[i][10] || 0;
        break;
      }
    }

    if (!tanggalMasuk) return 0;

    var cutiData = cutiSheet ? cutiSheet.getDataRange().getDisplayValues() : [];
    var approvedLeaves = [];
    for (var ci = 1; ci < cutiData.length; ci++) {
      var cutiNama = cutiData[ci][1] ? cutiData[ci][1].toString().trim().toLowerCase() : '';
      var status = cutiData[ci][12] ? cutiData[ci][12].toString() : '';
      if (cutiNama === targetName && status === 'Disetujui') {
        approvedLeaves.push({ tglMulai: cutiData[ci][6], lama: cutiData[ci][8] });
      }
    }

    var massLeaveDates = getMassLeaveDatesFromSS(ss);
    return calculateUsableQuota(tanggalMasuk, approvedLeaves, staticQuotaVal, massLeaveDates);
  } catch (e) { return 0; }
}


// ============================================================
// CRUD KARYAWAN
// ============================================================

function simpanKaryawanBaru(data) {
  try {
    let securePassword = hashPassword(data.password);
    let rowContent = [data.id, data.ptName || "-", data.nama, data.email, securePassword, data.peran, data.divisi, data.jabatan, data.tanggalMasuk || "", data.status || "Aktif", data.sisaCuti];
    if (data.extended && Array.isArray(data.extended)) {
      rowContent = rowContent.concat(data.extended);
    }
    SpreadsheetApp.openByUrl(SHEET_URL).getSheetByName(KARYAWAN_SHEET_NAME).appendRow(rowContent);
    return { success: true, message: 'Karyawan ditambahkan.' };
  } catch (e) { return { success: false, message: e.message }; }
}

function updateKaryawan(data) {
  try {
    const sheet = SpreadsheetApp.openByUrl(SHEET_URL).getSheetByName(KARYAWAN_SHEET_NAME);
    const sheetData = sheet.getDataRange().getDisplayValues();
    for (let i = 1; i < sheetData.length; i++) {
      if (sheetData[i][0].toString() === data.id.toString()) {
        sheet.getRange(i + 1, 2).setValue(data.ptName || "-");
        sheet.getRange(i + 1, 3).setValue(data.nama);
        sheet.getRange(i + 1, 4).setValue(data.email);
        if (data.password && data.password.trim() !== '') {
          sheet.getRange(i + 1, 5).setValue(hashPassword(data.password));
        }
        sheet.getRange(i + 1, 6).setValue(data.peran);
        sheet.getRange(i + 1, 7).setValue(data.divisi);
        sheet.getRange(i + 1, 8).setValue(data.jabatan);
        if (data.tanggalMasuk !== undefined) sheet.getRange(i + 1, 9).setValue(data.tanggalMasuk);
        if (data.status !== undefined) sheet.getRange(i + 1, 10).setValue(data.status);
        sheet.getRange(i + 1, 11).setValue(data.sisaCuti);
        if (data.extended && Array.isArray(data.extended) && data.extended.length > 0) {
          sheet.getRange(i + 1, 12, 1, data.extended.length).setValues([data.extended]);
        }
        return { success: true, message: 'Data diupdate.' };
      }
    }
    return { success: false, message: 'Karyawan tidak ditemukan.' };
  } catch (e) { return { success: false, message: e.message }; }
}

/**
 * updateMasterCuti — Hanya update tanggalMasuk dan sisaCuti (legacy quota 2025).
 * Tidak mempengaruhi kalkulasi FIFO untuk cuti 2026+.
 */
function updateMasterCuti(data) {
  try {
    const sheet = SpreadsheetApp.openByUrl(SHEET_URL).getSheetByName(KARYAWAN_SHEET_NAME);
    const sheetData = sheet.getDataRange().getDisplayValues();
    for (let i = 1; i < sheetData.length; i++) {
      if (sheetData[i][0].toString() === data.id.toString()) {
        sheet.getRange(i + 1, 9).setValue(data.tanggalMasuk || "");
        sheet.getRange(i + 1, 11).setValue(data.sisaCuti); // Kolom 11 (1-indexed) = index 10
        return { success: true, message: 'Data Master Cuti diupdate.' };
      }
    }
    return { success: false, message: 'Karyawan tidak ditemukan.' };
  } catch (e) { return { success: false, message: e.message }; }
}

function hapusKaryawan(id) {
  try {
    const sheet = SpreadsheetApp.openByUrl(SHEET_URL).getSheetByName(KARYAWAN_SHEET_NAME);
    const data = sheet.getDataRange().getDisplayValues();
    for (let i = 1; i < data.length; i++) {
      if (data[i][0].toString() === id.toString()) {
        sheet.deleteRow(i + 1);
        return { success: true, message: 'Karyawan dihapus.' };
      }
    }
    return { success: false, message: 'Karyawan tidak ditemukan.' };
  } catch (e) { return { success: false, message: e.message }; }
}


