// ATK (LOGISTIK)
// ============================================================

function getPendingRequests() {
  const ss = SpreadsheetApp.openByUrl(SHEET_URL);
  const data = ss.getSheetByName(REQUEST_LOG_SHEET_NAME).getDataRange().getDisplayValues();
  const ptMap = getEmployeePtMap();
  const requests = [];
  for (let i = 1; i < data.length; i++) {
    if (data[i][7] === 'Menunggu Persetujuan') {
      const email = data[i][3];
      requests.push({
        rowNum: i + 1,
        timestamp: data[i][1],
        employeeName: data[i][2],
        department: data[i][4],
        itemName: data[i][5],
        quantity: data[i][6],
        ptName: ptMap[email.toString().trim().toLowerCase()] || "-"
      });
    }
  }
  return requests;
}

function processApproval(rowNum, isApproved, reason) {
  try {
    SpreadsheetApp.openByUrl(SHEET_URL).getSheetByName(REQUEST_LOG_SHEET_NAME).getRange(rowNum, 8).setValue(isApproved ? 'Disetujui' : `Ditolak: ${reason}`);
    return { success: true, message: 'Status diupdate.' };
  } catch (e) { return { success: false, message: e.message }; }
}

function getConfirmedProofRecords() {
  const ss = SpreadsheetApp.openByUrl(SHEET_URL);
  const data = ss.getSheetByName(REQUEST_LOG_SHEET_NAME).getDataRange().getDisplayValues();
  const ptMap = getEmployeePtMap();
  const records = [];
  for (let i = data.length - 1; i > 0; i--) {
    if (data[i][7] === 'Sudah Diambil' || (data[i][8] && data[i][8].toString().includes('http'))) {
      const email = data[i][3];
      records.push({
        rowNum: i + 1,
        timestamp: data[i][1],
        employeeName: data[i][2],
        department: data[i][4],
        itemName: data[i][5],
        quantity: data[i][6],
        proofLink: data[i][8],
        ptName: ptMap[email.toString().trim().toLowerCase()] || "-"
      });
    }
  }
  return records;
}

function addStock(name, qty) {
  try {
    const sheet = SpreadsheetApp.openByUrl(SHEET_URL).getSheetByName(ATK_LIST_SHEET_NAME);
    const data = sheet.getDataRange().getDisplayValues();
    for (let i = 1; i < data.length; i++) {
      if (data[i][0] === name) {
        const currentStock = parseInt(data[i][1]) || 0;
        sheet.getRange(i + 1, 2).setValue(currentStock + parseInt(qty));
        return { success: true, message: `Stok ${name} ditambah.` };
      }
    }
    return { success: false, message: 'Barang tak ditemukan.' };
  } catch (e) { return { success: false, message: e.message }; }
}

function addNewItem(name, stock, limit) {
  try {
    SpreadsheetApp.openByUrl(SHEET_URL).getSheetByName(ATK_LIST_SHEET_NAME).appendRow([name, stock, limit]);
    return { success: true, message: 'Barang baru ditambahkan.' };
  } catch (e) { return { success: false, message: e.message }; }
}


// ============================================================
// DASHBOARD DATA
// ============================================================

function getDashboardData() {
  try {
    const atkData = SpreadsheetApp.openByUrl(SHEET_URL).getSheetByName(ATK_LIST_SHEET_NAME).getDataRange().getDisplayValues();
    const reqData = SpreadsheetApp.openByUrl(SHEET_URL).getSheetByName(REQUEST_LOG_SHEET_NAME).getDataRange().getDisplayValues();
    const cutiData = SpreadsheetApp.openByUrl(SHEET_URL).getSheetByName(CUTI_SHEET_NAME).getDataRange().getDisplayValues();
    const karData = SpreadsheetApp.openByUrl(SHEET_URL).getSheetByName(KARYAWAN_SHEET_NAME).getDataRange().getDisplayValues();

    const lowStockItems = [];
    for (let i = 1; i < atkData.length; i++) {
      let stock = parseInt(atkData[i][1]) || 0;
      let threshold = parseInt(atkData[i][2]) || 5;
      if (stock <= threshold && atkData[i][0]) lowStockItems.push({ name: atkData[i][0], stock, threshold });
    }

    let itemCounts = {}, deptCounts = {};
    for (let i = 1; i < reqData.length; i++) {
      let dept = reqData[i][4], item = reqData[i][5], qty = parseInt(reqData[i][6]) || 0;
      if (item) itemCounts[item] = (itemCounts[item] || 0) + qty;
      if (dept) deptCounts[dept] = (deptCounts[dept] || 0) + 1;
    }
    const topItems = Object.entries(itemCounts).sort((a, b) => b[1] - a[1]).slice(0, 5);
    const topDepts = Object.entries(deptCounts).sort((a, b) => b[1] - a[1]);

    const totalKaryawan = karData.length > 1 ? karData.length - 1 : 0;
    let totalMenungguCuti = 0, sedangCutiCount = 0, cutiMendatang = [];
    let jenisCutiCount = {}, employeeLeaveFreq = {};
    let trendData = {};
    for (let m = 5; m >= 0; m--) {
      let d = new Date(); d.setMonth(d.getMonth() - m);
      let monthName = d.toLocaleString('id-ID', { month: 'short' });
      trendData[monthName] = 0;
    }
    let now = new Date(); now.setHours(0, 0, 0, 0);

    for (let i = 1; i < cutiData.length; i++) {
      let timestampRaw = cutiData[i][0];
      let nama = cutiData[i][1];
      let status = cutiData[i][12] ? cutiData[i][12].toString() : '';
      let jenis = cutiData[i][5];
      let tglMulaiRaw = cutiData[i][6];
      let tglSelesaiRaw = cutiData[i][7];

      if (status.includes('Menunggu')) totalMenungguCuti++;
      if (jenis && !status.includes('Ditolak')) {
        jenisCutiCount[jenis] = (jenisCutiCount[jenis] || 0) + 1;
        if (nama) employeeLeaveFreq[nama] = (employeeLeaveFreq[nama] || 0) + 1;
      }
      if (timestampRaw) {
        let tsDate = new Date(timestampRaw);
        let mName = tsDate.toLocaleString('id-ID', { month: 'short' });
        if (trendData[mName] !== undefined) trendData[mName]++;
      }
      if (status === 'Disetujui' && tglMulaiRaw && tglSelesaiRaw) {
        let tglMulai = new Date(tglMulaiRaw); tglMulai.setHours(0, 0, 0, 0);
        let tglSelesai = new Date(tglSelesaiRaw); tglSelesai.setHours(23, 59, 59, 999);
        if (now >= tglMulai && now <= tglSelesai) sedangCutiCount++;
        else if (tglMulai > now) cutiMendatang.push({ nama, jenis, tglMulai: tglMulaiRaw, tglSelesai: tglSelesaiRaw, lama: cutiData[i][8] });
      }
    }

    let topEmpName = "-", topEmpFreq = 0;
    for (let emp in employeeLeaveFreq) {
      if (employeeLeaveFreq[emp] > topEmpFreq) { topEmpFreq = employeeLeaveFreq[emp]; topEmpName = emp; }
    }
    cutiMendatang.sort((a, b) => new Date(a.tglMulai) - new Date(b.tglMulai));

    return {
      lowStockItems, topItems, topDepts,
      cutiStats: {
        totalKaryawan, pengajuanBaru: totalMenungguCuti, sedangCuti: sedangCutiCount,
        jadwalMendatang: cutiMendatang.slice(0, 5),
        distribusi: Object.entries(jenisCutiCount),
        topEmployee: { name: topEmpName, count: topEmpFreq },
        trendLabels: Object.keys(trendData),
        trendValues: Object.values(trendData)
      }
    };
  } catch (e) {
    return { lowStockItems: [], topItems: [], topDepts: [], cutiStats: { totalKaryawan: 0, pengajuanBaru: 0, sedangCuti: 0, jadwalMendatang: [], distribusi: [], topEmployee: { name: '-', count: 0 }, trendLabels: [], trendValues: [] } };
  }
}

function downloadReport(start, end) {
  try {
    const data = SpreadsheetApp.openByUrl(SHEET_URL).getSheetByName(REQUEST_LOG_SHEET_NAME).getDataRange().getDisplayValues();
    let csvData = data[0].join(',') + '\n';
    const startDate = start ? new Date(start) : null;
    const endDate = end ? new Date(end) : null;
    if (endDate) endDate.setHours(23, 59, 59);
    for (let i = 1; i < data.length; i++) {
      let rowDate = new Date(data[i][1]); let include = true;
      if (startDate && rowDate < startDate) include = false;
      if (endDate && rowDate > endDate) include = false;
      if (include) { let row = data[i].map(cell => `"${cell.toString().replace(/"/g, '""')}"`); csvData += row.join(',') + '\n'; }
    }
    return { success: true, csv: csvData };
  } catch (e) { return { success: false, message: e.message }; }
}

function ubahPassword(email, oldPassword, newPassword) {
  try {
    const sheet = SpreadsheetApp.openByUrl(SHEET_URL).getSheetByName(KARYAWAN_SHEET_NAME);
    const data = sheet.getDataRange().getDisplayValues();
    const inputOldHash = hashPassword(oldPassword);
    const newHash = hashPassword(newPassword);
    for (let i = 1; i < data.length; i++) {
      if (data[i][3].toString().trim().toLowerCase() === email.trim().toLowerCase()) {
        let dbPassword = data[i][4].toString().trim();
        if (dbPassword === inputOldHash || dbPassword === oldPassword) {
          sheet.getRange(i + 1, 5).setValue(newHash);
          return { success: true, message: 'Password berhasil diperbarui! Silakan login kembali.' };
        } else {
          return { success: false, message: 'Password lama salah.' };
        }
      }
    }
    return { success: false, message: 'Akun tidak ditemukan.' };
  } catch (e) { return { success: false, message: 'Terjadi kesalahan: ' + e.message }; }
}


