/**
 * getEmployeePtMap — Map karyawan ke PT (by name dan email).
 */
function getEmployeePtMap() {
  try {
    const sheet = SpreadsheetApp.openByUrl(SHEET_URL).getSheetByName(KARYAWAN_SHEET_NAME);
    const lastRow = sheet.getLastRow();
    if (lastRow < 2) return {};
    const data = sheet.getRange(1, 1, lastRow, 15).getDisplayValues();
    const map = {};
    for (let i = 1; i < data.length; i++) {
      const name = data[i][2] ? data[i][2].toString().trim().toLowerCase() : "";
      const email = data[i][3] ? data[i][3].toString().trim().toLowerCase() : "";
      const pt = data[i][1] || "";
      if (name) map[name] = pt;
      if (email) map[email] = pt;
    }
    return map;
  } catch (e) { return {}; }
}